## Integration Patterns

### Sender-Side Cancellation

```rust
use asupersync::cancel::symbol::*;

async fn send_with_cancellation(
    sender: &mut RaptorQSender<T>,
    broadcaster: &CancelBroadcaster,
    object_id: ObjectId,
    data: &[u8],
    rng: &mut DetRng,
) -> Result<ObjectParams> {
    // Create cancellation token
    let token = SymbolCancelToken::new(object_id, rng);
    broadcaster.register_token(token.clone());

    // Encode
    let symbols = encode(data)?;

    // Transmit with cancellation checks
    for symbol in symbols {
        // Check for cancellation
        if token.is_cancelled() {
            let reason = token.reason().unwrap_or_else(CancelReason::default);
            return Err(Error::cancelled(&reason));
        }

        sender.send_symbol(symbol).await?;
    }

    // Unregister token on success
    broadcaster.unregister_token(&object_id);

    Ok(params)
}

// To cancel from another task:
// broadcaster.cancel(object_id, CancelReason::user("user requested"), Time::now()).await?;
```

### Receiver-Side Cancellation

```rust
async fn receive_with_cancellation(
    receiver: &mut RaptorQReceiver<S>,
    broadcaster: &CancelBroadcaster,
    cleanup: &CleanupCoordinator,
    params: &ObjectParams,
    rng: &mut DetRng,
) -> Result<Vec<u8>> {
    let token = SymbolCancelToken::new(params.object_id, rng);
    broadcaster.register_token(token.clone());

    loop {
        // Check cancellation
        if token.is_cancelled() {
            // Trigger cleanup
            cleanup.cleanup(params.object_id, None);
            broadcaster.unregister_token(&params.object_id);

            let reason = token.reason().unwrap_or_else(CancelReason::default);
            return Err(Error::cancelled(&reason));
        }

        // Receive symbol
        match receiver.recv().await? {
            Some(symbol) => {
                cleanup.register_pending(params.object_id, symbol.clone(), Time::now());

                // Try decode
                if can_decode(&symbol) {
                    let data = decode()?;
                    cleanup.clear_pending(&params.object_id);
                    broadcaster.unregister_token(&params.object_id);
                    return Ok(data);
                }
            }
            None => {
                return Err(Error::new(ErrorKind::StreamEnded));
            }
        }
    }
}
```

### Handling Incoming Cancellation Messages

```rust
async fn handle_cancel_messages(
    broadcaster: &CancelBroadcaster,
    messages: impl Stream<Item = CancelMessage>,
) {
    pin_mut!(messages);

    while let Some(msg) = messages.next().await {
        let now = Time::now();
        if let Err(e) = broadcaster.handle_message(msg, now).await {
            log::warn!("Failed to handle cancel message: {}", e);
        }
    }
}
