### Cancel During Acquire
```rust
#[cfg(test)]
mod cancel_safety_tests {
    #[test]
    fn cancel_during_acquire_wait_releases_waiter() {
        init_pool_test_logging();

        let pool = GenericPool::new(
            || async { Ok(MockConnection::new()) },
            PoolConfig { max_connections: 1, ..Default::default() },
        );

        let lab = LabRuntimeBuilder::new().rng_seed(42).build();

        lab.run_with_cx(|cx| async move {
            // Exhaust the pool
            let held = pool.acquire(&cx).await.unwrap();

            // Spawn a task that waits for a connection
            let handle = cx.spawn(async {
                tracing::debug!("Waiter starting acquire");
                pool.acquire(&cx).await
            });

            // Give it time to start waiting
            sleep(Duration::from_millis(10)).await;

            // Cancel the waiter
            handle.cancel(CancelReason::user("test cancel"));

            // Wait for cancellation
            let result = handle.join().await;
            assert!(matches!(result, Outcome::Cancelled(_)));

            // Pool should not be corrupted
            held.return_to_pool();
            assert_eq!(pool.stats().idle, 1);

            tracing::info!("Cancel during wait handled correctly");
        });
    }

    #[test]
    fn cancel_while_holding_returns_resource_in_drain() {
        init_pool_test_logging();

        let pool = GenericPool::new(...);
        let returned = Arc::new(AtomicBool::new(false));
        let returned2 = returned.clone();

        let lab = LabRuntimeBuilder::new().rng_seed(42).build();

        lab.run_with_cx(|cx| async move {
            let handle = cx.spawn(async move {
                let resource = pool.acquire(&cx).await.unwrap();

                // Register drain handler
                cx.defer_async(|| async move {
                    resource.return_to_pool();
                    returned2.store(true, Ordering::SeqCst);
                });

                // Simulate long work
                loop {
                    yield_now().await;
                }
            });

            // Cancel the task
            sleep(Duration::from_millis(10)).await;
            handle.cancel(CancelReason::user("test"));
            handle.join().await;

            // Resource should have been returned in drain phase
            assert!(returned.load(Ordering::SeqCst));
            assert_eq!(pool.stats().idle, 1);

            tracing::info!("Drain phase returned resource correctly");
        });
    }
}
